=== PebbleBitmap.kt ===
package io.rebble.libpebblecommon.image

/**
 * A platform- and UI-framework-agnostic bitmap: ARGB8888 pixels in row-major order.
 *
 * This is a pure-Kotlin type (no Compose/AndroidX dependency) so it can appear in the
 * published common API surface (e.g. screenshots, contact images, app icons) without
 * forcing Compose onto consumers. Convert it to a Compose `ImageBitmap` with the
 * `PebbleBitmap.toImageBitmap()` extension (in the `util` package) when rendering.
 */
class PebbleBitmap(
    val width: Int,
    val height: Int,
    /** ARGB8888 pixels, row-major, length == width * height. */
    val pixels: IntArray,
) {
    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is PebbleBitmap) return false
        return width == other.width && height == other.height && pixels.contentEquals(other.pixels)
    }

    override fun hashCode(): Int {
        var result = width
        result = 31 * result + height
        result = 31 * result + pixels.contentHashCode()
        return result
    }
}
